import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import createAxiosInstance from "../../config/api";
import "../../config/index.css";
import InstitutionSchedule from "../utils/InstitutionSchedule";

function PersonneScheduleRegi() {
  const { Id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [editedItem, setEditedItem] = useState({});
  const today = new Date();  // 정확히 Date 객체로 생성합니다.
  const todayDate = today.toISOString().split("T")[0]; // 오늘 날짜 (YYYY-MM-DD)
  const todayTime = today.toLocaleTimeString('ko-KR', { hour: '2-digit', minute: '2-digit' }); // 시간 (초 제외)

  const handleSave = async (e) => {
    e.preventDefault(); // 폼 제출 방지
    const confirmSave = window.confirm("해당 일정을 추가하시겠습니까?");
    if (!confirmSave) {
      return;
    } else {
      setLoading(true);
      try {
        const axiosInstance = createAxiosInstance(); // 인스턴스 생성
        const response = await axiosInstance.put(
            `/personnel/institution/${Id}/schedule/add`,
            editedItem
        );
        window.alert("일정을 추가 하였습니다");
        setLoading(false);
        navigate(-1);
      } catch (err) {
        if (err.response && err.response.status === 404) {
          // 404 에러에 대한 처리
          window.alert("입력된 값을 다시 한번 확인해 주세요");
        } else {
          // 기타 에러에 대한 처리
          setError("일정을 추가하는데 실패했습니다.");
        }
      }
    }
  };


  const handleChange = (e) => {
    const { name, value } = e.target;
    setEditedItem((prevItem) => ({
      ...prevItem,
      [name]: value,
    }));
  };

  const handleGoBack = () => {
    navigate(-1);
  };

  if (loading) return <p style={styles.errorMessage}>Loading...</p>;
  if (error) return <p style={styles.errorMessage}>{error}</p>;

  return (
      <div className="detail-container">
        {editedItem && (
            <div style={styles.card}>
              <div style={styles.cardHeader}>
                <h3>스케쥴 신규 추가 페이지</h3>
              </div>
              <div style={styles.cardBody}>
                <form onSubmit={handleSave}>
                  <div className="form-group">
                    <label>일정 이름</label>
                    <input
                        name="name"
                        onChange={handleChange}
                        className="input"
                        required
                    />
                  </div>
                  <div className="form-group">
                    <label>내용</label>
                    <textarea
                        type="text"
                        name="scheduleInfo"
                        onChange={handleChange}
                        className="input"
                        required
                    />
                  </div>
                  <div className="form-group">
                    <label>시작일, 시간</label>
                    <div style={{ display: "flex", gap: "10px", alignItems: "center" }}>
                      {/* 날짜 선택 */}
                      <input
                          type="date"
                          name="startDateTime"
                          value={todayDate}
                          // startDateTime에서 날짜 부분만 추출
                          onChange={(e) => {
                            const dateValue = e.target.value;
                            setEditedItem((prev) => {
                              const time = prev.startDateTime?.split("T")[1] || "00:00";
                              // 기존 시간 유지 또는 기본값
                              return {
                                ...prev,
                                startDateTime: `${dateValue}T${time}`,
                                // 날짜와 기존 시간을 조합
                              };
                            });
                          }}
                          className="input"
                          required
                      />
                      {/* 시간 선택 */}
                      <input
                          type="time"
                          name="startDateTime"
                          value={todayTime} // 기본값
                          onChange={(e) => {
                            const timeValue = e.target.value;
                            setEditedItem((prev) => {
                              const date = prev.startDateTime?.split("T")[0] || new Date().toISOString().split("T")[0]; // 기존 날짜 유지 또는 기본값
                              return {
                                ...prev,
                                startDateTime: `${date}T${timeValue}`, // 기존 날짜와 시간을 조합
                              };
                            });
                          }}
                          className="input"
                          required
                      />
                    </div>
                  </div>
                  <div className="form-group">
                    <label>종료일, 시간</label>
                    <div style={{ display: "flex", gap: "10px", alignItems: "center" }}>
                      {/* 날짜 선택 */}
                      <input
                          type="date"
                          name="endDateTime"
                          value={todayDate}
                          onChange={(e) => {
                            const dateValue = e.target.value;
                            setEditedItem((prev) => {
                              const time = prev.endDateTime?.split("T")[1] || "00:00"; // 기존 시간 유지 또는 기본값
                              return {
                                ...prev,
                                endDateTime: `${dateValue}T${time}`, // 날짜와 기존 시간을 조합
                              };
                            });
                          }}
                          className="input"
                          required
                      />
                      {/* 시간 선택 */}
                      <input
                          type="time"
                          name="endDateTime"
                          value={todayTime} // 기본값
                          onChange={(e) => {
                            const timeValue = e.target.value;
                            setEditedItem((prev) => {
                              const date = prev.endDateTime?.split("T")[0] || new Date().toISOString().split("T")[0]; // 기존 날짜 유지 또는 기본값
                              return {
                                ...prev,
                                endDateTime: `${date}T${timeValue}`, // 기존 날짜와 시간을 조합
                              };
                            });
                          }}
                          className="input"
                          required
                      />
                    </div>
                  </div>
                  <div className="form-group">
                    <label>일정</label>
                    <select
                        name="scheduleType"
                        onChange={handleChange}
                        className="input"
                        required
                    >
                      <option value="" disabled>
                        일정 종류를 선택해 주세요
                      </option>
                      <option value="면접">면접</option>
                      <option value="기관">기관</option>
                      <option value="이벤트">이벤트</option>
                      <option value="기타">기타</option>
                      <option value="회계">회계</option>
                    </select>
                  </div>
                  <button type="submit" className="submit-button">
                    저장
                  </button>
                </form>
                <button className="submit-button" onClick={handleGoBack}>
                  돌아가기
                </button>
              </div>
            </div>
        )}
      </div>
  );
}

const styles = {
  container: {
    padding: "20px",
    max_width: "600px",
    margin: "0 auto",
    background: "#f9f9f9",
  },
  card: {
    boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
    borderRadius: "4px",
    overflow: "hidden",
  },
  cardHeader: {
    backgroundColor: "#007bff",
    color: "#fff",
    padding: "10px",
  },
  cardBody: {
    padding: "20px",
  },
